import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { PantryService } from '../../../services/pantry.service';
import { PantryItem, Category, Household } from '../../../models/models';

@Component({
  selector: 'app-pantry-item-form',
  templateUrl: './pantry-item-form.component.html',
  styleUrls: ['./pantry-item-form.component.css']
})


export class PantryItemFormComponent implements OnInit {
  @Input() household!: Household;
  @Input() item: PantryItem | null = null;
  @Input() categories: Category[] = [];
  @Output() saved = new EventEmitter<void>();
  @Output() cancelled = new EventEmitter<void>();

  form: FormGroup;
  loading = false;
  error = '';

  units = ['units', 'g', 'kg', 'ml', 'l', 'tsp', 'tbsp', 'cup'];
  statuses = ['available', 'low', 'consumed', 'wasted'];

  constructor(private fb: FormBuilder, private pantryService: PantryService) {
    this.form = this.fb.group({
      name: ['', Validators.required],
      category_id: [null],
      quantity: [1, [Validators.required, Validators.min(0)]],
      unit: ['units', Validators.required],
      expiry_date: [null],
      status: ['available', Validators.required],
      notes: ['']
    });
  }

  ngOnInit(): void {
    if (this.item) {
      this.form.patchValue({
        ...this.item,
        category_id: this.item.category?.id ?? null,
      });
    }
  }

  submit(): void {
    if (this.form.invalid) return;
    this.loading = true;
    this.error = '';
    const data: any = { ...this.form.value, household: this.household.id };
    if (!data.expiry_date) delete data.expiry_date;
    if (!data.category_id) data.category_id = null;

    const obs = this.item
      ? this.pantryService.updateItem(this.item.id, data)
      : this.pantryService.createItem(data);

    obs.subscribe({
      next: () => { this.loading = false; this.saved.emit(); },
      error: (err) => {
        const errors = err.error;
        if (errors) {
          this.error = Object.entries(errors).map(([k, v]) => `${k}: ${(v as string[]).join(', ')}`).join(' | ');
        } else {
          this.error = 'Failed to save item.';
        }
        this.loading = false;
      }
    });
  }
}
<div class="modal-overlay" (click)="cancelled.emit()">
  <div class="modal" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <h2>{{ item ? 'Edit Item' : 'Add Pantry Item' }}</h2>
      <button class="modal-close" (click)="cancelled.emit()">x</button>
    </div>

    <div class="alert alert-danger" *ngIf="error">{{ error }}</div>

    <form [formGroup]="form" (ngSubmit)="submit()">
      <div class="form-group">
        <label>Name *</label>
        <input class="form-control" formControlName="name" placeholder="e.g. Chicken Breast"
          [class.is-invalid]="form.get('name')?.invalid && form.get('name')?.touched">
        <div class="error-msg" *ngIf="form.get('name')?.errors?.['required'] && form.get('name')?.touched">
          Name is required
        </div>
      </div>

      <div class="form-row-2">
        <div class="form-group">
          <label>Quantity *</label>
          <input class="form-control" type="number" formControlName="quantity"
            min="0" step="any" placeholder="0">
        </div>
        <div class="form-group">
          <label>Unit *</label>
          <select class="form-control" formControlName="unit">
            <option *ngFor="let u of units" [value]="u">{{ u }}</option>
          </select>
        </div>
      </div>

      <div class="form-row-2">
        <div class="form-group">
          <label>Category</label>
          <select class="form-control" formControlName="category_id">
            <option [value]="null">- None -</option>
            <option *ngFor="let cat of categories" [value]="cat.id">
              {{ cat.name }}
            </option>
          </select>
        </div>
        <div class="form-group">
          <label>Status</label>
          <select class="form-control" formControlName="status">
            <option *ngFor="let s of statuses" [value]="s">{{ s }}</option>
          </select>
        </div>
      </div>

      <div class="form-group">
        <label>Expiry Date</label>
        <input class="form-control" type="date" formControlName="expiry_date">
      </div>

      <div class="form-group">
        <label>Notes</label>
        <textarea class="form-control" formControlName="notes"
          rows="2" placeholder="Optional notes..."></textarea>
      </div>

      <div class="modal-footer">
        <button type="button" class="btn btn-secondary" (click)="cancelled.emit()">Cancel</button>
        <button type="submit" class="btn btn-primary" [disabled]="form.invalid || loading">
          {{ loading ? 'Saving...' : (item ? 'Update' : 'Add Item') }}
        </button>
      </div>
    </form>
  </div>
</div>
